def get_rotated_vertices(x, y, yaw, length, width):
    half_l = length / 2.0
    half_w = width / 2.0
    local_vertices = [
        (-half_l, -half_w),
        (half_l, -half_w),
        (half_l, half_w),
        (-half_l, half_w)
    ]
    cos_yaw = math.cos(yaw)
    sin_yaw = math.sin(yaw)
    rotated_vertices = []
    for (lx, ly) in local_vertices:
        rx = lx * cos_yaw - ly * sin_yaw
        ry = lx * sin_yaw + ly * cos_yaw
        rotated_vertices.append((x + rx, y + ry))
    return rotated_vertices


def project_vertices(vertices, axis):
    min_proj = float('inf')
    max_proj = -float('inf')
    for (x, y) in vertices:
        proj = x * axis[0] + y * axis[1]
        min_proj = min(min_proj, proj)
        max_proj = max(max_proj, proj)
    return (min_proj, max_proj)


def intervals_overlap(interval1, interval2):
    return not (interval1[1] < interval2[0] or interval2[1] < interval1[0])


def rectangles_intersect(x1, y1, yaw1, l1, w1, x2, y2, yaw2, l2, w2):
    rect1 = get_rotated_vertices(x1, y1, yaw1, l1, w1)
    rect2 = get_rotated_vertices(x2, y2, yaw2, l2, w2)
    axes = []
    for i in range(4):
        v1, v2 = rect1[i], rect1[(i + 1) % 4]
        edge = (v2[0] - v1[0], v2[1] - v1[1])
        axis = (-edge[1], edge[0])
        length = math.hypot(axis[0], axis[1])
        if length == 0:
            continue
        axis = (axis[0] / length, axis[1] / length)
        axes.append(axis)
    for i in range(4):
        v1, v2 = rect2[i], rect2[(i + 1) % 4]
        edge = (v2[0] - v1[0], v2[1] - v1[1])
        axis = (-edge[1], edge[0])
        length = math.hypot(axis[0], axis[1])
        if length == 0:
            continue
        axis = (axis[0] / length, axis[1] / length)
        axes.append(axis)
    for axis in axes:
        min1, max1 = project_vertices(rect1, axis)
        min2, max2 = project_vertices(rect2, axis)
        if not intervals_overlap((min1, max1), (min2, max2)):
            return False
    return True


